import { Tooltip } from ':components/Tooltip';
import { Typography } from ':components/Typography';
import { shallowEqual } from ':helpers/shallowEqual';
import type { ReactNode } from 'react';
import React, { isValidElement } from 'react';

import type { Option } from './Select.types';
import { CheckboxType } from './Select.types';

/**
 * Сравнивает два значения с учетом compareBy
 */
// eslint-disable-next-line id-length
export const compareValues = <T,>(a: T, b: T, compareBy?: string | ((a: T, b: T) => boolean)): boolean => {
	// Если передана функция сравнения, используем её
	if (typeof compareBy === 'function') {
		return compareBy(a, b);
	}

	// Если передан ключ для сравнения, сравниваем по этому ключу
	if (typeof compareBy === 'string') {
		return (a as any)[compareBy] === (b as any)[compareBy];
	}

	// По умолчанию используем shallowEqual
	return shallowEqual(a, b);
};

export const getPreparedOptions = <T extends { value?: string }>(
	options: Array<Option<T>>,
	filter?: boolean,
	filterValue?: string,
	filterFunction?: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>,
): Array<Option<T>> => {
	if (filter && filterValue && filterFunction) {
		return filterFunction(options, filterValue);
	}

	if (filter && filterValue && !filterFunction) {
		return options.filter(opt => {
			const currentStringValue = opt?.value?.value ?? String(opt.value);
			return currentStringValue.toString().toLowerCase().includes(filterValue.toLowerCase());
		});
	}

	return options;
};

/**
 * Возвращает опции в порядке отображения при группировке (как в Options).
 * Без groups возвращает options как есть.
 */
export const getOptionsInDisplayOrder = <T,>(
	options: Array<Option<T>>,
	groups?: Array<Option<string>>,
): Array<Option<T>> => {
	if (!groups || groups.length === 0) {
		return options;
	}
	return groups.flatMap(group => options.filter(opt => (opt.value as { groupID?: string })?.groupID === group.id));
};

export const defaultRenderValue = <T,>(values: T[]): string =>
	values?.map(val => (val as { value: string })?.value ?? val).join(', ');

export const defaultMakeOption = <T,>(option: T, showTooltip: boolean): React.JSX.Element => {
	const value = (option as { value: string })?.value ?? String(option);
	return (
		<Tooltip title={value} disableHover={!showTooltip}>
			<Typography variant="body2" ellipsis={true}>
				{value}
			</Typography>
		</Tooltip>
	);
};

export const getLoading = (loadingContent: string | React.ReactNode): ReactNode =>
	isValidElement(loadingContent) ? (
		loadingContent
	) : (
		<span style={{ padding: '4px 16px 2px 16px' }}>{loadingContent || 'Загрузка...'}</span>
	);

export const getCheckboxStatus = <T,>(
	options: Array<Option<T>>,
	selectedValues: Array<Option<T>>,
	filterValue: string,
	filter: boolean,
	filterFunction: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>,
	compareBy?: string | ((a: T, b: T) => boolean),
): CheckboxType => {
	const filteredOptions = getPreparedOptions(options, filter, filterValue, filterFunction);
	const enabledFilteredOptions = filteredOptions.filter(opt => !opt.disabled);

	const selectedFilteredValues = selectedValues.filter(val =>
		enabledFilteredOptions.some(opt => compareValues(opt.value, val.value, compareBy)),
	);

	if (enabledFilteredOptions.length === 0) {
		return CheckboxType.UNCHECKED;
	}

	if (selectedFilteredValues.length === enabledFilteredOptions.length) {
		return CheckboxType.CHECKED;
	}

	if (selectedFilteredValues.length === 0) {
		return CheckboxType.UNCHECKED;
	}

	return CheckboxType.PARTIALLY;
};
